INSERT INTO `apicompany` (`name`, `description`, `long_description`, `folder`, `dateupdated`, `staffid`) VALUES
('Bordignon & Bordignon - Advogados', 'Nosso propósito é tornar as questões jurídicas empresariais mais simples, claras e seguras para você, com orientação estratégica, linguagem acessível e compromisso com resultados. INSERT INTO `apicompany_goals` (`id`, `name`, `description`, `link`, `dateadded`, `staffid`, `order`) VALUES
(1, 'Visão', '<p>Incentivar a geração de empregos focados em conhecimento, tecnologia e inovação.</p>', NULL, '2025-01-15 10:22:34', 1, 0),
(2, 'Valores', '<ul><li>Ética, Respeito e Honestidade; INSERT INTO `apicompany_items` (`id`, `name`, `description`, `folder`, `file_name`, `link`, `dateadded`, `staffid`, `order`) VALUES
(1, 'Missão', '<p>Cultivar a eficiência tributária na agroindústria.</p>', NULL, NULL, NULL, '2025-07-17 11:36:13', 1, 0),
(2, 'Visão', '<p>Somos o suporte jurídico que protege, orienta e fortalece empresas em todas as fases do seu crescimento.</p>', NULL, 'education-1.svg', NULL, '2025-07-17 11:36:26', 1, 1),
(3, 'Valores', '<ul><li>Confiança;</li><li>Parceria;</li><li>Qualidade;</li><li>Inovação.</li></ul>', 'company', 'company-1.svg', NULL, '2025-07-17 13:11:09', 1, 2);
