INSERT INTO `apiposts` (`id`, `name`, `description`, `long_description`, `slug`, `clientid`, `billing_type`, `dateadded`, `staffid`, `contact_notification`, `notify_contacts`, `active`, `order`, `external_link`) VALUES
(1, 'Enfrentando o desafio dinâmico do controle de N-nitrosaminas.', 'Ser uma pessoa neurodivergente significa ter uma forma de processar a informação e experimentar o mundo que difere do padrão considerado típico ou neurotípico.', '<p>Ser uma pessoa neurodivergente significa ter uma forma de processar a informação e experimentar o mundo que difere do padrão considerado típico ou neurotípico. Pessoas neurodivergentes podem ter habilidades e perspectivas únicas que podem ser valiosas em diversos contextos. No entanto, também podem enfrentar desafios em áreas como comunicação, interação social, regulação sensorial ou organização.</p><p><br></p><p>Enquanto a terapia ABA é uma abordagem baseada em evidências que utiliza técnicas de análise do comportamento para melhorar habilidades sociais, de comunicação e de aprendizagem, o Modelo Denver é uma abordagem que se concentra no desenvolvimento de crianças com TEA através de jogos e atividades lúdicas.</p><p><br></p><p>O curso, com 372 horas de duração, será 100% presencial, com aulas quinzenais. As disciplinas incluem fundamentos da ABA e do Modelo Denver, avaliação e elaboração de planos educacionais individualizados, implementação de estratégias educacionais e terapêuticas, metodologias ágeis e ativas, interdisciplinaridade na prática educacional, tecnologia educacional e inovação, e reflexão crítica na prática docente.</p>', 'enfrentando-o-desafio-dinamico-do-controle-de-n-nitrosaminas', 0, NULL, '2025-01-07 13:55:35', 1, 1, NULL, 1, 1, NULL);
