INSERT INTO `apiprojects` (`id`, `name`, `description`, `long_description`, `slug`, `city`, `year`, `clientid`, `billing_type`, `dateadded`, `staffid`, `contact_notification`, `notify_contacts`, `active`, `order`) VALUES
(1, 'Edifício Petrópolis', 'Viver bem é estar aqui.', '<p>Com 112 apartamentos distribu&#237;dos em 17 pavimentos, o Edif&#237;cio Petr&#243;polis &#233; sin&#244;nimo de impon&#234;ncia, comodidade e lazer. Oferecemos 4 plantas diferentes, incluindo studios e apartamentos com su&#237;te, al&#233;m de op&#231;&#245;es com vista para o Lago Municipal de Toledo.</p><p><br></p><p>Uma excelente escolha para morar ou investir, com sacada e churrasqueira, sal&#227;o de festas, academia e muito mais.</p><p><br></p><p>O Edif&#237;cio Petr&#243;polis definitivamente reflete o esp&#237;rito da modernidade em Toledo. Situado em uma &#225;rea extremamente privilegiada, a mobilidade se multiplica e aproxima o centro, mas sem perder a tranquilidade plena e arborizada. Pr&#243;ximo ao shopping, parques e com&#233;rcio, aqui voc&#234; pode desfrutar a cidade do seu jeito, seja de bike, carro ou a p&#233;, voltando para casa sempre em conforto.</p>', 'edificio-petropolis', NULL, NULL, 0, NULL, '2025-01-17 12:52:41', 1, 1, NULL, 1, 1),
(2, 'Residencial Boa Ventura', 'Residencial Boa Ventura', '<p>Residencial Boa Ventura</p>', 'residencial-boa-ventura', NULL, NULL, 0, NULL, '2025-04-28 16:34:43', 1, 1, NULL, 1, 1);
