INSERT INTO `apiservices` (`id`, `name`, `description`, `slug`, `folder`, `file_name`, `dateadded`, `staffid`, `order`) VALUES
(1, 'Empresarial', '<p>Enquanto você foca no crescimento, a gente cuida da segurança jurídica do seu negócio.</p><p>Na rotina empresarial, cada decisão importa e cada detalhe jurídico também. Por isso, a Bordignon &amp; Bordignon oferece uma assessoria jurídica completa, estratégica e próxima, feita sob medida para proteger seu patrimônio, fortalecer relações comerciais e garantir conformidade legal em todas as etapas do seu negócio.</p><p><br></p><p><strong>Aqui, você encontra:</strong></p><p><br></p><p>Blindagem jurídica empresarial: prevenção de riscos e proteção do patrimônio pessoal dos sócios;</p><ul><li>Elaboração e revisão de contratos: claros, objetivos e juridicamente sólidos;</li><li>Consultoria estratégica contínua: suporte para tomadas de decisão com segurança;</li><li>Governança, compliance e estrutura societária: para empresas que querem crescer com responsabilidade;</li><li>Gestão preventiva de passivos trabalhistas, tributários e civis. INSERT INTO `apisessions` (`id`, `ip_address`, `timestamp`, `data`) VALUES
